import { __decorate } from "tslib";
import { ChangeDetectionStrategy, Component, EventEmitter, Input, Output, ViewEncapsulation, } from '@angular/core';
import { LucideAngularModule, ChevronLeft, ChevronRight } from 'lucide-angular';
function buildPageList(page, totalPages, siblings) {
    const compact = 2 * siblings + 5;
    if (totalPages <= compact) {
        return Array.from({ length: totalPages }, (_, i) => i + 1);
    }
    const pages = [];
    const left = Math.max(2, page - siblings);
    const right = Math.min(totalPages - 1, page + siblings);
    pages.push(1);
    if (left > 2)
        pages.push('ellipsis');
    for (let i = left; i <= right; i++)
        pages.push(i);
    if (right < totalPages - 1)
        pages.push('ellipsis');
    pages.push(totalPages);
    return pages;
}
/**
 * Pagination accessible : `<nav>` + `<ol>` + boutons.
 * Émet `(pageChange)` ; c'est l'app qui met à jour son état.
 */
let OriPaginationComponent = class OriPaginationComponent {
    constructor() {
        this.page = 1;
        this.totalPages = 1;
        this.siblings = 1;
        this.ariaLabel = 'Pagination';
        this.pageChange = new EventEmitter();
        this.pages = [];
        this.ChevronLeftIcon = ChevronLeft;
        this.ChevronRightIcon = ChevronRight;
    }
    get canPrev() {
        return this.page > 1;
    }
    get canNext() {
        return this.page < this.totalPages;
    }
    ngOnChanges(_changes) {
        this.pages = buildPageList(this.page, this.totalPages, this.siblings);
    }
